import React, { useState, useEffect, useRef } from 'react';
import Webcam from 'react-webcam';
import { employeeAPI, departmentAPI } from '../utils/api';
import toast from 'react-hot-toast';
import './EmployeePage.css';

const EMPTY_FORM = { employee_id: '', name: '', name_kh: '', department: '', position: '', phone: '', email: '' };

export default function EmployeePage() {
  const [employees, setEmployees] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [search, setSearch] = useState('');
  const [filterDept, setFilterDept] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState(EMPTY_FORM);
  const [saving, setSaving] = useState(false);
  const [faceModal, setFaceModal] = useState(null); // employee obj
  const [capturing, setCapturing] = useState(false);
  const webcamRef = useRef(null);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);

  useEffect(() => { loadData(); }, [search, filterDept, page]);
  useEffect(() => { departmentAPI.list().then(r => setDepartments(r.data.results || r.data)); }, []);

  const loadData = async () => {
    const params = { page };
    if (search) params.search = search;
    if (filterDept) params.department = filterDept;
    const res = await employeeAPI.list(params);
    setEmployees(res.data.results || res.data);
    setTotal(res.data.count || 0);
  };

  const handleSave = async () => {
    if (!form.employee_id || !form.name) return toast.error('Employee ID and Name required');
    setSaving(true);
    try {
      const fd = new FormData();
      Object.entries(form).forEach(([k, v]) => v && fd.append(k, v));
      await employeeAPI.create(fd);
      toast.success('Employee created!');
      setForm(EMPTY_FORM);
      setShowForm(false);
      loadData();
    } catch (e) {
      toast.error(e.response?.data?.employee_id?.[0] || 'Error saving');
    } finally { setSaving(false); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this employee?')) return;
    await employeeAPI.delete(id);
    toast.success('Deleted');
    loadData();
  };

  const captureAndRegister = async () => {
    if (!webcamRef.current || !faceModal) return;
    setCapturing(true);
    try {
      const imgSrc = webcamRef.current.getScreenshot();
      if (!imgSrc) return toast.error('Could not capture image');
      const res = await employeeAPI.registerFace(faceModal.id, imgSrc);
      toast.success('✅ Face registered successfully!');
      setFaceModal(null);
      loadData();
    } catch (e) {
      toast.error(e.response?.data?.error || 'Registration failed');
    } finally { setCapturing(false); }
  };

  const filtered = employees.filter(e =>
    (!search || e.name.toLowerCase().includes(search.toLowerCase()) || e.employee_id.includes(search)) &&
    (!filterDept || String(e.department) === String(filterDept))
  );

  return (
    <div>
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
        <div><h1>👥 Employees</h1><p>Total: {total} employees</p></div>
        <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
          {showForm ? '✕ Cancel' : '+ Add Employee'}
        </button>
      </div>

      {showForm && (
        <div className="card" style={{ marginBottom: 20 }}>
          <div className="card-title">New Employee</div>
          <div className="emp-form-grid">
            {[
              { key: 'employee_id', label: 'Employee ID *', ph: 'EMP001' },
              { key: 'name', label: 'Name (EN) *', ph: 'Sophea Chan' },
              { key: 'name_kh', label: 'ឈ្មោះ (KH)', ph: 'ចាន់ សូភា' },
              { key: 'position', label: 'Position', ph: 'Operator' },
              { key: 'phone', label: 'Phone', ph: '012 345 678' },
              { key: 'email', label: 'Email', ph: 'sophea@factory.com' },
            ].map(f => (
              <div key={f.key}>
                <label>{f.label}</label>
                <input value={form[f.key]} placeholder={f.ph} onChange={e => setForm({ ...form, [f.key]: e.target.value })} />
              </div>
            ))}
            <div>
              <label>Department</label>
              <select value={form.department} onChange={e => setForm({ ...form, department: e.target.value })}>
                <option value="">— Select —</option>
                {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
            </div>
          </div>
          <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
            <button className="btn btn-primary" onClick={handleSave} disabled={saving}>{saving ? 'Saving...' : '💾 Save'}</button>
          </div>
        </div>
      )}

      {/* Filter bar */}
      <div className="filter-bar">
        <input placeholder="🔍 Search by name or ID..." value={search}
          onChange={e => { setSearch(e.target.value); setPage(1); }} style={{ maxWidth: 300 }} />
        <select value={filterDept} onChange={e => { setFilterDept(e.target.value); setPage(1); }} style={{ maxWidth: 200 }}>
          <option value="">All Departments</option>
          {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
        </select>
      </div>

      {/* Table */}
      <div className="card">
        <div className="emp-table-wrap">
          <table className="live-table">
            <thead>
              <tr>
                <th>ID</th><th>Name</th><th>Khmer Name</th><th>Department</th>
                <th>Position</th><th>Face</th><th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(emp => (
                <tr key={emp.id}>
                  <td><code style={{ color: '#60a5fa' }}>{emp.employee_id}</code></td>
                  <td style={{ fontWeight: 500 }}>{emp.name}</td>
                  <td style={{ fontFamily: 'serif' }}>{emp.name_kh || '—'}</td>
                  <td>{emp.department_name || '—'}</td>
                  <td>{emp.position || '—'}</td>
                  <td>
                    <span className={`badge ${emp.has_face ? 'badge-green' : 'badge-red'}`}>
                      {emp.has_face ? '✅ Yes' : '❌ No'}
                    </span>
                  </td>
                  <td>
                    <div style={{ display: 'flex', gap: 6 }}>
                      <button className="btn btn-secondary" style={{ padding: '4px 10px', fontSize: 12 }}
                        onClick={() => setFaceModal(emp)}>
                        📷 Face
                      </button>
                      <button className="btn btn-danger" style={{ padding: '4px 10px', fontSize: 12 }}
                        onClick={() => handleDelete(emp.id)}>
                        🗑️
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr><td colSpan={7} style={{ textAlign: 'center', padding: 40, color: '#475569' }}>No employees found</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Face Register Modal */}
      {faceModal && (
        <div className="modal-overlay" onClick={() => setFaceModal(null)}>
          <div className="modal-box" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <div>
                <div style={{ fontWeight: 700, fontSize: 16 }}>📷 Register Face</div>
                <div style={{ fontSize: 13, color: '#94a3b8' }}>{faceModal.name} ({faceModal.employee_id})</div>
              </div>
              <button className="btn btn-secondary" onClick={() => setFaceModal(null)} style={{ padding: '4px 10px' }}>✕</button>
            </div>
            <div className="webcam-wrap">
              <Webcam
                ref={webcamRef}
                screenshotFormat="image/jpeg"
                width="100%"
                videoConstraints={{ width: 640, height: 480, facingMode: 'user' }}
                style={{ borderRadius: 8, display: 'block' }}
              />
              <div className="face-guide-box" />
            </div>
            <div style={{ padding: 16, display: 'flex', gap: 10 }}>
              <button className="btn btn-success" style={{ flex: 1 }} onClick={captureAndRegister} disabled={capturing}>
                {capturing ? '⏳ Registering...' : '📸 Capture & Register'}
              </button>
              <button className="btn btn-secondary" onClick={() => setFaceModal(null)}>Cancel</button>
            </div>
            <div style={{ padding: '0 16px 16px', fontSize: 12, color: '#64748b' }}>
              💡 Position face clearly in the center. Ensure good lighting. Only one face in frame.
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
